<?php
namespace App\Http\Controllers\CommandCenter\Compliance;
use App\Http\Controllers\Controller; use App\Models\Compliance\GstDocumentNote; use App\Models\Crm\CrmInvoice; use App\Services\Compliance\GstNoteService; use Illuminate\Http\RedirectResponse; use Illuminate\Http\Request; use Illuminate\View\View;
class GstNoteController extends Controller { public function index(Request $r):View{$notes=GstDocumentNote::query()->where('company_id',$r->user()->company_id)->latest('issue_date')->paginate(25);$invoices=CrmInvoice::query()->where('company_id',$r->user()->company_id)->where('status','issued')->latest('issue_date')->limit(100)->get();return view('command-center.compliance.gst.notes',compact('notes','invoices'));} public function store(Request $r,GstNoteService $service):RedirectResponse{$data=$r->validate(['invoice_id'=>['required','integer'],'note_type'=>['required','in:credit,debit'],'reason_description'=>['required','string','max:2000'],'taxable_value'=>['required','numeric','min:0.01'],'grand_total'=>['required','numeric','min:0.01'],'cgst_total'=>['nullable','numeric','min:0'],'sgst_total'=>['nullable','numeric','min:0'],'igst_total'=>['nullable','numeric','min:0'],'cess_total'=>['nullable','numeric','min:0']]);$invoice=CrmInvoice::query()->where('company_id',$r->user()->company_id)->findOrFail($data['invoice_id']);$service->create($invoice,$r->user(),$data);return back()->with('status','GST note created as draft.');} }
